class Solution:
    def hasValidPath(self, grid):
        # Union-Find approach: for each cell union with right/down neighbor if connection is valid
        CONNECTS = {
            1: {(0, -1), (0, 1)},
            2: {(-1, 0), (1, 0)},
            3: {(0, -1), (1, 0)},
            4: {(0, 1), (1, 0)},
            5: {(0, -1), (-1, 0)},
            6: {(0, 1), (-1, 0)},
        }
        m, n = len(grid), len(grid[0])
        parent = list(range(m * n))

        def find(x):
            while parent[x] != x:
                parent[x] = parent[parent[x]]
                x = parent[x]
            return x

        def union(x, y):
            px, py = find(x), find(y)
            if px != py:
                parent[px] = py

        for r in range(m):
            for c in range(n):
                tile = grid[r][c]
                for dr, dc in CONNECTS[tile]:
                    nr, nc = r + dr, c + dc
                    if 0 <= nr < m and 0 <= nc < n:
                        nbr_tile = grid[nr][nc]
                        if (-dr, -dc) in CONNECTS[nbr_tile]:
                            union(r * n + c, nr * n + nc)
        return find(0) == find((m - 1) * n + (n - 1))

