class Solution:
    def hasValidPath(self, grid):
        from collections import deque
        CONNECTS = {
            1: [(0, -1), (0, 1)],
            2: [(-1, 0), (1, 0)],
            3: [(0, -1), (1, 0)],
            4: [(0, 1), (1, 0)],
            5: [(0, -1), (-1, 0)],
            6: [(0, 1), (-1, 0)],
        }
        m, n = len(grid), len(grid[0])
        visited = [[False] * n for _ in range(m)]
        visited[0][0] = True
        q = deque([(0, 0)])
        while q:
            r, c = q.popleft()
            if r == m - 1 and c == n - 1:
                return True
            for dr, dc in CONNECTS[grid[r][c]]:
                nr, nc = r + dr, c + dc
                if 0 <= nr < m and 0 <= nc < n and not visited[nr][nc]:
                    if (-dr, -dc) in CONNECTS[grid[nr][nc]]:
                        visited[nr][nc] = True
                        q.append((nr, nc))
        return visited[m - 1][n - 1]

